  1	import * as React from 'react';
  2	import { CORSRule, GetBucketCorsCommandOutput } from '@aws-sdk/client-s3';
  3	import {
  4	  S3Provider,
  5	  S3Context,
  6	} from '@odf/core/components/s3-browser/s3-context';
  7	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  8	import { StatusBox } from '@odf/shared/generic/status-box';
  9	import { isNoCorsRuleError } from '@odf/shared/s3/utils';
 10	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 11	import { deepSortObject } from '@odf/shared/utils';
 12	import * as _ from 'lodash-es';
 13	import { murmur3 } from 'murmurhash-js';
 14	import { useNavigate, useParams } from 'react-router-dom-v5-compat';
 15	import useSWR from 'swr';
 16	import {
 17	  TextVariants,
 18	  Text,
 19	  TextContent,
 20	  Divider,
 21	  Button,
 22	  ButtonVariant,
 23	} from '@patternfly/react-core';
 24	import { BUCKET_CORS_RULE_CACHE_KEY_SUFFIX } from '../../../constants';
 25	import { CorsFormContents } from './CorsFormContents';
 26	import {
 27	  ruleReducer,
 28	  ruleInitialState,
 29	  RuleActionType,
 30	  RuleState,
 31	} from './reducer';
 32	import { useEditCorsRule } from './useEditCorsRule';
 33	import { isInvalidCorsRule } from './validations';
 34	
 35	type IsEditProp = { isEdit?: boolean };
 36	
 37	const getRuleConfig = (state: RuleState): CORSRule => {
 38	  const allowedOrigins = state.allowedOrigins;
 39	  const allowedMethods = state.allowedMethods;
 40	  const allowedHeaders = state.allowedHeaders;
 41	  const exposedHeaders = state.exposedHeaders;
 42	  const maxAge = state.maxAge;
 43	
 44	  return {
 45	    ID: state.name,
 46	    ...(!!allowedHeaders.length ? { AllowedHeaders: allowedHeaders } : {}),
 47	    AllowedMethods: allowedMethods,
 48	    AllowedOrigins: allowedOrigins,
 49	    ...(!!exposedHeaders.length ? { ExposeHeaders: exposedHeaders } : {}),
 50	    ...(!!maxAge ? { MaxAgeSeconds: maxAge } : {}),
 51	  };
 52	};
 53	
 54	const createNewRule = (
 55	  state: RuleState,
 56	  latestRules: GetBucketCorsCommandOutput
 57	) => {
 58	  const currRules: CORSRule[] =
 59	    latestRules?.CORSRules?.filter((rule) => rule.ID !== state.name) || [];
 60	  const newRule: CORSRule = getRuleConfig(state);
 61	
 62	  return [...currRules, newRule];
 63	};
 64	
 65	const updateExistingRule = (
 66	  state: RuleState,
 67	  latestRules: GetBucketCorsCommandOutput,
 68	  ruleName: string,
 69	  ruleHash: string
 70	) => {
 71	  let filteredRules: CORSRule[];
 72	  if (!!ruleName) {
 73	    filteredRules =
 74	      latestRules?.CORSRules?.filter(
 75	        (rule) => rule.ID !== ruleName && rule.ID !== state.name
 76	      ) || [];
 77	  } else if (!!ruleHash) {
 78	    // fallback if rule name (ID) is missing
 79	    filteredRules =
 80	      latestRules?.CORSRules?.filter(
 81	        (rule) =>
 82	          `${murmur3(JSON.stringify(deepSortObject(rule)))}` !== ruleHash &&
 83	          rule.ID !== state.name
 84	      ) || [];
 85	  } else {
 86	    filteredRules = latestRules?.CORSRules || [];
 87	  }
 88	  const updateRule: CORSRule = getRuleConfig(state);
 89	
 90	  return [...filteredRules, updateRule];
 91	};
 92	
 93	const Header: React.FC<IsEditProp> = ({ isEdit }) => {
 94	  const { t } = useCustomTranslation();
 95	
 96	  return (
 97	    <>
 98	      <TextContent>
 99	        <Text component={TextVariants.h1}>
100	          {isEdit ? t('Edit CORS rule') : t('Create CORS rule')}
101	        </Text>
102	        <Text component={TextVariants.small}>
103	          {t(
104	            'The CORS configuration, defines a way for client web applications that are loaded in one domain to interact with resources in a different domain.'
105	          )}
106	        </Text>
107	      </TextContent>
108	      <Divider className="pf-v6-u-my-lg" />
109	    </>
110	  );
111	};
112	
113	const CreateOrEditCorsForm: React.FC<IsEditProp> = ({ isEdit }) => {
114	  const { t } = useCustomTranslation();
115	
116	  const { bucketName } = useParams();
117	  const navigate = useNavigate();
118	  const { s3Client } = React.useContext(S3Context);
119	
120	  const [inProgress, setInProgress] = React.useState<boolean>(false);
121	  const [putError, setPutError] = React.useState<Error>();
122	  const [state, dispatch] = React.useReducer(ruleReducer, ruleInitialState);
123	
124	  const {
125	    data,
126	    isLoading,
127	    error: getError,
128	    mutate,
129	  } = useSWR(
130	    `${s3Client.providerType}-${bucketName}-${BUCKET_CORS_RULE_CACHE_KEY_SUFFIX}`,
131	    () => s3Client.getBucketCors({ Bucket: bucketName }),
132	    {
133	      shouldRetryOnError: false,
134	    }
135	  );
136	
137	  const noRuleExistsError = isNoCorsRuleError(getError);
138	  // in case of "noRuleExistsError" error, cache could still have older "data", hence clearing that.
139	  const existingRules = noRuleExistsError ? undefined : data;
140	
141	  const [ruleName, ruleHash] = useEditCorsRule({
142	    isEdit,
143	    existingRules,
144	    dispatch,
145	  });
146	
147	  const onSave = async (event) => {
148	    event.preventDefault();
149	    setInProgress(true);
150	
151	    if (isInvalidCorsRule(state, existingRules, isEdit, ruleName)) {
152	      dispatch({
153	        type: RuleActionType.TRIGGER_INLINE_VALIDATIONS,
154	        payload: true,
155	      });
156	      setInProgress(false);
157	    } else {
158	      try {
159	        let latestRules: GetBucketCorsCommandOutput;
160	
161	        try {
162	          latestRules = await s3Client.getBucketCors({ Bucket: bucketName });
163	        } catch (err) {
164	          if (isNoCorsRuleError(err)) {
165	            latestRules = { CORSRules: [] } as GetBucketCorsCommandOutput;
166	          } else {
167	            throw err;
168	          }
169	        }
170	
171	        await s3Client.putBucketCors({
172	          Bucket: bucketName,
173	          CORSConfiguration: {
174	            CORSRules: isEdit
175	              ? updateExistingRule(state, latestRules, ruleName, ruleHash)
176	              : createNewRule(state, latestRules),
177	          },
178	        });
179	
180	        setInProgress(false);
181	        mutate();
182	        navigate(-1);
183	      } catch (err) {
184	        setInProgress(false);
185	        setPutError(err);
186	      }
187	    }
188	  };
189	
190	  if (isLoading || (getError && !noRuleExistsError)) {
191	    return (
192	      <StatusBox loaded={!isLoading} loadError={isLoading ? '' : getError} />
193	    );
194	  }
195	
196	  return (
197	    <div className="pf-v6-u-m-md">
198	      <Header isEdit={isEdit} />
199	      <CorsFormContents
200	        state={state}
201	        dispatch={dispatch}
202	        existingRules={existingRules}
203	        isEdit={isEdit}
204	        editingRuleName={ruleName}
205	      />
206	      <ButtonBar
207	        inProgress={inProgress}
208	        errorMessage={putError?.message || JSON.stringify(putError)}
209	        className="pf-v6-u-mt-lg pf-v6-u-mb-md"
210	      >
211	        <span>
212	          <Button
213	            variant={ButtonVariant.primary}
214	            onClick={onSave}
215	            isDisabled={inProgress}
216	            className="pf-v6-u-mr-xs"
217	          >
218	            {isEdit ? t('Save') : t('Create')}
219	          </Button>
220	          <Button
221	            variant={ButtonVariant.secondary}
222	            onClick={() => navigate(-1)}
223	            className="pf-v6-u-ml-xs"
224	          >
225	            {t('Cancel')}
226	          </Button>
227	        </span>
228	      </ButtonBar>
229	    </div>
230	  );
231	};
232	
233	export const CreateCorsRule: React.FC<{}> = () => (
234	  <S3Provider>
235	    <CreateOrEditCorsForm />
236	  </S3Provider>
237	);
238	
239	export const EditCorsRule: React.FC<{}> = () => (
240	  <S3Provider>
241	    <CreateOrEditCorsForm isEdit />
242	  </S3Provider>
243	);

